import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import { TextField, Button, Typography, Box } from "@mui/material";

const EditDrug = () => {
    const { id } = useParams(); // Lấy ID thuốc từ URL
    const navigate = useNavigate();

    const [drug, setDrug] = useState({
        code: "",
        name: "",
        typeId: "",
        price: "",
        unit: "",
        description: "",
    });

    // Gọi API lấy dữ liệu thuốc theo ID
    useEffect(() => {
        axios
            .get(`http://localhost:3001/api/drugs/${id}`)
            .then((response) => {
                setDrug(response.data); // Cập nhật state với dữ liệu từ API
            })
            .catch((error) => {
                console.error("Lỗi khi lấy dữ liệu thuốc:", error);
            });
    }, [id]);

    // Hàm xử lý thay đổi input
    const handleChange = (e) => {
        setDrug({ ...drug, [e.target.name]: e.target.value });
    };

    // Hàm cập nhật thuốc
    const handleUpdate = (e) => {
        e.preventDefault();
        axios
            .put(`http://localhost:3001/api/drugs/${id}`, drug)
            .then(() => {
                alert("Cập nhật thành công!");
                navigate("/drugs"); // Chuyển về danh sách thuốc sau khi cập nhật
            })
            .catch((error) => {
                console.error("Lỗi khi cập nhật thuốc:", error);
            });
    };

    return (
        <Box>
            <Typography variant="h4">Chỉnh sửa thuốc</Typography>
            <form onSubmit={handleUpdate}>
                <TextField label="Mã thuốc" name="code" value={drug.code} onChange={handleChange} fullWidth margin="normal" />
                <TextField label="Tên thuốc" name="name" value={drug.name} onChange={handleChange} fullWidth margin="normal" />
                <TextField label="ID Loại thuốc" name="typeId" value={drug.typeId} onChange={handleChange} fullWidth margin="normal" />
                <TextField label="Giá" name="price" value={drug.price} onChange={handleChange} fullWidth margin="normal" />
                <TextField label="Đơn vị" name="unit" value={drug.unit} onChange={handleChange} fullWidth margin="normal" />
                <TextField label="Mô tả" name="description" value={drug.description} onChange={handleChange} fullWidth margin="normal" multiline rows={4} />

                <Button variant="contained" color="primary" type="submit">Lưu lại</Button>
                <Button variant="outlined" color="secondary" onClick={() => navigate("/drugs")} style={{ marginLeft: "10px" }}>Quay lại</Button>
            </form>
        </Box>
    );
};

export default EditDrug;
